$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_30327841e3afbdd1e3a14a2cf328570e'] = 'Ta opcja pozwala na ładowanie pixela dopiero po kompletnym załadowaniu strony. W niektórych przypadkach, czas ładowania strony znacznie się zmniejszy, lecz istnieje ryzyko, że zdarzenia wywołane przed załadowaniem pixela, nie będą śledzone.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_71c6dc1af52ebbfa10df384604a8a9e3'] = 'Opóźnienie tylko pierwszego ładowania';
$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_12f9dfc9f516d3bb7dda55cf5a31f004'] = 'Wysoce rekomendowana opcja, jeżeli decydujesz się na użycie trybu opóźnienia. Ograniczenie będzie opóźnione tylko do pierwszego ładowania. Gdy już skrypt będzie załadowany w cache przeglądarki, skrypt będzie ładowany bez opóźnień i wszystkie akcje będą dostępne znacznie szybciej.';
