$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_c7f846b5f8b98ab8b04139d46ed97d77'] = 'Moduł próbuje wydobyć piksele z dołu strony, dzięki temu JavaScript nie blokuje renderowania strony';
